.team {
  padding: 2em 1em 5em 1em;
}

.team-row {
  display: flex;
  gap: 8em;
  margin-bottom: 4em;
}

.team-member {
  flex: 1;
}

.team-info {
  position: relative;
  top: 20px;
  opacity: 0;
  transition: all 0.3s;
}

.team-member:hover .team-info {
  top: 5px;
  opacity: 1;
}

.about-subhero {
