}

.about-page .hero-visions {
  background: var(--color-accent-bg);
}

.hovers {
  padding: 4em 1em 4em 1em;
  display: flex;
  gap: 1em;
}

.hovers > div {
  flex: 1;
}

.hover-item {
  display: flex;
  justify-content: space-between;
  margin-bottom: 0.3em;
}

@media (max-width: 900px) {
  .team-row {
    flex-direction: column;
    gap: 3em;
